import json

# Check available variables
for name in list(locals().keys()):
    print(name)

# Try to find our query result
result_key = None
for key in locals().keys():
    if 'query_db:8' in str(key):
        result_key = key
        break

if result_key:
    print('Found result key:', result_key)
    result = locals()[result_key]
    print('Type:', type(result))
    if isinstance(result, str):
        print('Path to file:', result[:100])
        # Try to load JSON
        try:
            with open(result, 'r') as f:
                data = json.load(f)
            print('Loaded data count:', len(data))
        except Exception as e:
            print('Error loading file:', e)
else:
    print('Result key not found')

