import json
import re
from collections import defaultdict, Counter
import os

# Load patent data
patents_file = None
for key, value in locals().items():
    key_str = str(key)
    if 'query_db:42' in key_str and isinstance(value, str) and '.json' in value:
        patents_file = value
        break

if not patents_file:
    result = {'error': 'No patents file found'}
else:
    with open(patents_file, 'r') as f:
        patents = json.load(f)

    # Filter for second half
    month_patterns = ['jul', 'aug', 'sep', 'oct', 'nov', 'dec']
    second_half = []
    for p in patents:
        date = p.get('grant_date', '').lower()
        for mp in month_patterns:
            if mp in date:
                second_half.append(p)
                break

    # Extract CPC level 4
    level4_counts = defaultdict(int)
    for p in second_half:
        cpc = p.get('cpc', '')
        codes = re.findall(r'"code"\s*:\s*"([^"]+)"', cpc)
        for code in codes:
            parts = code.split('/')
            if len(parts) == 2:
                level4 = parts[0]
                level4_counts[level4] += 1

    top_15 = sorted(level4_counts.items(), key=lambda x: x[1], reverse=True)[:15]

    result = {
        'total_patents': len(second_half),
        'total_level4_groups': len(level4_counts),
        'top_groups': [{'code': code, 'count': count} for code, count in top_15]
    }

print('__RESULT__:')
print(json.dumps(result))

